int main(int argc, char * argv[])
{

	int version = 13;
	double start, stop;

	Input input = read_CLI( argc, argv );

	omp_set_num_threads(input.nthreads);

	logo(version);
	center_print("INPUT SUMMARY", 79);
	border_print();
