	}

	stop = get_time();

	vhash %= 999983;

	printf("Simulation Complete.\n");

	border_print();
	center_print("RESULTS", 79);
	border_print();

	int is_invalid = validate_and_print_results(input, stop-start, vhash, sim_runtime);

	border_print();

	return is_invalid;
}

