void fancy_int( int a )
{
    if( 1000 > a )
        printf("%d\n",a);

    else if( 1000 <= a && 1000000 > a )
        printf("%d,%03d\n", a / 1000, a % 1000);

    else if( 1000000 <= a && 1000000000 > a )
        printf("%d,%03d,%03d\n", a / 1000000, (a % 1000000) / 1000, a % 1000 );

    else if( 1000000000 <= a )
        printf("%d,%03d,%03d,%03d\n",
               a / 1000000000,
               (a % 1000000000) / 1000000,
               (a % 1000000) / 1000,
               a % 1000 );
    else
        printf("%d\n",a);
}

Input read_CLI( int argc, char * argv[] )
{
	Input input;

	input.simulation_method = HISTORY_BASED;

	input.nthreads = 1;

	input.n_nuclides = 355;

	input.particles = 300000;

	input.lookups = 34;

	input.HM = LARGE;

	input.avg_n_poles = 1000;

	input.avg_n_windows = 100;

	input.numL = 4;

	input.doppler = 1;

	input.kernel_id = 0;

  input.platform_id = -1;
  input.device_id = -1;

  int default_lookups = 1;
  int default_particles = 1;

  for( int i = 1; argc > i; i++ )
  {
    char * arg = argv[i];

    if( 0 == strcmp(arg, "-m") )
    {
      char * sim_type = NULL;
      if( ++i < argc )
        sim_type = argv[i];
      else
        print_CLI_error();

      if( 0 == strcmp(sim_type, "history") )
        input.simulation_method = HISTORY_BASED;
      else if( 0 == strcmp(sim_type, "event") )
      {
        input.simulation_method = EVENT_BASED;

        if( default_lookups && default_particles )
        {
          input.lookups =  input.lookups * input.particles;
          input.particles = 0;
        }
      }
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-l") )
    {
      if( ++i < argc )
      {
        input.lookups = atoi(argv[i]);
        default_lookups = 0;
      }
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-p") )
    {
      if( ++i < argc )
      {
        input.particles = atoi(argv[i]);
        default_particles = 0;
      }
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-n") )
    {
      if( ++i < argc )
        input.n_nuclides = atoi(argv[i]);
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-s") )
    {	
      if( ++i < argc )
      {
        if( 0 == strcmp(argv[i], "small") )
          input.HM = SMALL;
        else if ( 0 == strcmp(argv[i], "large") )
          input.HM = LARGE;
        else
          print_CLI_error();
      }
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-d") )
    {	
      input.doppler = 0;
    }

    else if( 0 == strcmp(arg, "-W") )
    {
      if( ++i < argc )
        input.avg_n_windows = atoi(argv[i]);
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-p") )
    {
      if( ++i < argc )
        input.avg_n_poles = atoi(argv[i]);
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-k") )
    {
      if( ++i < argc )
        input.kernel_id = atoi(argv[i]);
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-P") )
    {
      if( ++i < argc )
      {
        input.platform_id = atoi(argv[i]);
        printf("PLATFORM ID DETECTED = %d\n", input.platform_id);
      }
      else
        print_CLI_error();
    }

    else if( 0 == strcmp(arg, "-D") )
    {
      if( ++i < argc )
        input.device_id = atoi(argv[i]);
      else
        print_CLI_error();
    }
    else
      print_CLI_error();
  }

  if( 1 > input.nthreads )
    print_CLI_error();

  if( 1 > input.n_nuclides )
    print_CLI_error();

  if( 1 > input.lookups )
    print_CLI_error();

  if( 1 > input.avg_n_poles )
    print_CLI_error();

  if( 1 > input.avg_n_windows )
    print_CLI_error();

  if( input.HM == SMALL )
    input.n_nuclides = 68;

  return input;
}

